patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index dad0d1e9ef55..39aa977429bf 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -11256,6 +11256,14 @@ BoUpSLP::ScalarsVectorizationLegality BoUpSLP::getScalarsVectorizationLegality(
 void BoUpSLP::buildTreeRec(ArrayRef<Value *> VLRef, unsigned Depth,
                            const EdgeInfo &UserTreeIdx,
                            unsigned InterleaveFactor) {
+  // We can't vectorize terminator instructions.
+  if (any_of(VLRef, [](Value *V) {
+        if (auto *I = dyn_cast<Instruction>(V))
+          return I->isTerminator();
+        return false;
+      }))
+    return;
+
   assert((allConstant(VLRef) || allSameType(VLRef)) && "Invalid types!");

   SmallVector<int> ReuseShuffleIndices;

